        std::suspend_always final_suspend() noexcept { return {}; }
        std::suspend_always yield_value(T value) noexcept {
            current_value = value;
            return {};
        }
        void return_void() noexcept {}
        void unhandled_exception() { std::terminate(); }
    };

    // Итератор для range-for
    struct iterator {
        std::coroutine_handle<promise_type> handle;
        bool done;

        iterator& operator++() {
            handle.resume();
            done = handle.done();
            return *this;
        }
        T operator*() const { return handle.promise().current_value; }
        bool operator==(std::default_sentinel_t) const { return done; }
    };

    std::coroutine_handle<promise_type> handle_;

    explicit Generator(std::coroutine_handle<promise_type> h) : handle_(h) {}

    // RAII: уничтожаем фрейм в деструкторе
    ~Generator() { if (handle_) handle_.destroy(); }

    // Некопируемый, перемещаемый
    Generator(const Generator&) = delete;
    Generator& operator=(const Generator&) = delete;
    Generator(Generator&& other) noexcept : handle_(std::exchange(other.handle_, {})) {}

    iterator begin() {
        handle_.resume(); // продвигаемся до первого co_yield
        return iterator{handle_, handle_.done()};
    }
    std::default_sentinel_t end() { return {}; }
};

Generator<int> range(int first, int last) {
    for (int i = first; i < last; ++i)
        co_yield i;
}

Generator<int> squares(int n) {
    for (int i = 1; i <= n; ++i)
        co_yield i * i;
}

int main() {
    std::cout << "range(1, 6): ";
    for (int v : range(1, 6))
        std::cout << v << ' ';
    std::cout << '\n';

    std::cout << "squares(5): ";
    for (int v : squares(5))
        std::cout << v << ' ';
    std::cout << '\n';
}

#include <coroutine>
#include <iostream>
#include <exception>
#include <stdexcept>
#include <utility>

template<typename T>
struct Generator {
    struct promise_type {
        T current_value;
        std::exception_ptr exception;   // храним вместо terminate()

        Generator get_return_object() {
            return Generator{std::coroutine_handle<promise_type>::from_promise(*this)};
        }
        std::suspend_always initial_suspend() noexcept { return {}; }
        std::suspend_always final_suspend() noexcept { return {}; }
        std::suspend_always yield_value(T value) noexcept {
            current_value = value;
            return {};
        }
        void return_void() noexcept {}
        // Вызывается внутри catch-блока — current_exception() работает
        void unhandled_exception() {
            exception = std::current_exception();
        }
    };

    struct iterator {
        std::coroutine_handle<promise_type> handle;
        bool done;

        iterator& operator++() {
            handle.resume();
            done = handle.done();
            // Если корутина завершилась с исключением — перебрасываем
            if (done && handle.promise().exception)
                std::rethrow_exception(handle.promise().exception);
            return *this;
        }
        T operator*() const { return handle.promise().current_value; }
        bool operator==(std::default_sentinel_t) const { return done; }
    };

    std::coroutine_handle<promise_type> handle_;

    explicit Generator(std::coroutine_handle<promise_type> h) : handle_(h) {}
    ~Generator() { if (handle_) handle_.destroy(); }
    Generator(const Generator&) = delete;
    Generator& operator=(const Generator&) = delete;
    Generator(Generator&& other) noexcept : handle_(std::exchange(other.handle_, {})) {}

    iterator begin() {
        handle_.resume();
        if (handle_.done() && handle_.promise().exception)
            std::rethrow_exception(handle_.promise().exception);
        return iterator{handle_, handle_.done()};
    }
    std::default_sentinel_t end() { return {}; }
};

Generator<int> maybe_throw(bool should_throw) {
    co_yield 1;
    if (should_throw)
        throw std::runtime_error("error in coroutine");
    co_yield 2;
    co_yield 3;
}

int main() {
    // Нормальный путь: без исключения
    std::cout << "Normal path: ";
    for (int v : maybe_throw(false))
        std::cout << v << ' ';
    std::cout << '\n';

    // Путь с исключением
    std::cout << "Exception path: ";
    try {
        for (int v : maybe_throw(true))
            std::cout << v << ' ';
    } catch (const std::exception& e) {
        std::cout << "\ncaught: " << e.what();
    }
    std::cout << '\n';
}

