// Бесконечный генератор: локальные переменные (a, b) живут между приостановками
Generator<long long> fibonacci() {
    long long a = 0, b = 1;
    while (true) {
        co_yield a;
        long long c = a + b;
        a = b;
        b = c;
    }
}

int main() {
    std::cout << "First 10 Fibonacci numbers:\n";
    int count = 0;
    for (long long v : fibonacci()) {
        std::cout << v << ' ';
        if (++count == 10) break; // ранний выход — деструктор уничтожает фрейм
    }
    std::cout << '\n';

    // Второй независимый генератор — каждый вызов fibonacci() создаёт свой фрейм
    std::cout << "First 5 from a new generator:\n";
    count = 0;
    for (long long v : fibonacci()) {
        std::cout << v << ' ';
        if (++count == 5) break;
    }
    std::cout << '\n';
}
